    padding: 0.5rem 0.75rem;
  }

  .layout {
    padding: 0.5rem;
  }

  .card {
    padding: 0.5rem;
  }

  textarea {
    padding: 0.5rem;
  }

  button {
    padding: 0.4rem 0.8rem;
  }
}

