/* Print styles */
@media print {
  .topbar,
  button {
    display: none;
  }

  body {
    background: white;
    color: black;
  }

  .card {
    box-shadow: none;
    border: 1px solid #ccc;
  }

  textarea {
    border: 1px solid #ccc;
  }
}

/* Focus states for accessibility */
button:focus {
  outline: 2px solid var(--quasar-yellow);
  outline-offset: 2px;
  box-shadow: 0 0 0 2px var(--event-horizon);
}

textarea:focus {
  outline: 2px solid var(--quasar-yellow);
  outline-offset: 2px;
  box-shadow: 0 0 0 2px var(--event-horizon);
}

/* Enhanced button hover states */
button:hover {
  transform: translateY(-2px);
  box-shadow: 0 5px 15px rgba(255, 107, 107, 0.3);
}

button:active {
  transform: translateY(0);
  box-shadow: 0 3px 10px rgba(255, 107, 107, 0.2);
}

/* Enhanced textarea focus states */
textarea:focus {
  transform: scale(1.01);
  transition: transform 0.2s ease;
}

/* Enhanced file content styling */
.file-content {
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
  line-height: 1.4;
  white-space: pre-wrap;
}

/* Enhanced pill styling */
.pill {
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

/* Black Hole-themed header */
.black-hole-header {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  padding: 1rem;
  text-align: center;
  color: var(--quasar-yellow);
}

.black-hole-greeting {
  font-size: 1.2rem;
  font-style: italic;
  margin-bottom: 0.5rem;
}

.black-hole-icons {
  display: flex;
  justify-content: center;
  gap: 0.5rem;
}

.black-hole-icon {
  font-size: 1.5rem;
  animation: rotate 3s linear infinite;
}

.black-hole-icon:nth-child(1) {
  animation-delay: 0s;
}

.black-hole-icon:nth-child(2) {
  animation-delay: 0.5s;
}

.black-hole-icon:nth-child(3) {
  animation-delay: 1s;
}

.black-hole-icon:nth-child(4) {
  animation-delay: 1.5s;
}

.black-hole-icon:nth-child(5) {
  animation-delay: 2s;
}

/* Black Hole-themed footer */
.black-hole-footer {
  margin-top: 2rem;
  padding-top: 1rem;
  border-top: 1px solid var(--quasar-yellow);
}

.black-hole-wishes {
  margin-bottom: 0.5rem;
  font-style: italic;
  color: var(--quasar-yellow);
}

.black-hole-scarab {
  font-size: 1.5rem;
  animation: rotate 3s linear infinite;
}

.black-hole-footer-decorations {
  display: flex;
  justify-content: center;
  gap: 0.5rem;
  font-size: 1.5rem;
}

.black-hole-event-horizon {
  animation: rotate 3s linear infinite;
}

.black-hole-accretion-disk {
  animation: spin 4s linear infinite;
}

.black-hole-stellar-remnant {
  animation: pulse 2s ease-in-out infinite;
}

.black-hole-wave {
  animation: rotate 5s linear infinite;
}

.black-hole-sun {
  animation: spin 6s linear infinite;
}

.black-hole-umbrella {
  animation: pulse 3s ease-in-out infinite;
}

.black-hole-seagull {
  animation: rotate 4s linear infinite;
}

